mapper.select:
SELECT we.*, po.order_no, a.apply_no, au.nickname AS approver_name FROM warehouse_entry we LEFT JOIN purchase_order po ON we.purchase_order_id = po.id LEFT JOIN asset_application a ON we.application_id = a.id LEFT JOIN sys_user au ON we.approver_id = au.user_id WHERE we.deleted = 0
AND we.status = #{status}
ORDER BY we.create_time DESC
